INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES (111031, "", "存外意義あるものだ\n資材ダイビングとか\nいう新種の探索行は", 10, "", 13020026, 11, 302, "", "", "");
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES (0, "", 1, "", "", 13020027, 91, 302, "", "", "");
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES (111031, "", "まあ万一溺れたとて\n後輩たちの誰ぞが\nきっと気付くだろう", 10, "", 13020028, 11, 302, "", "", "");
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES (0, "", 1, "", "", 13020029, 91, 302, "", "", "");
